package org.apache.commons.math3.analysis.differentiation;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.math3.analysis.differentiation.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math3.analysis.differentiation.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math3.analysis.differentiation.DerivativeStructure;

import static org.junit.Assert.assertEquals;

public class StepDefs {

    private DerivativeStructure y;
    private DerivativeStructure x;
    private DerivativeStructure result;

    @Given("^a DerivativeStructure \"y\" constructed with value (.+)$")
    public void a_DerivativeStructure_y_constructed_with_value(String y_val) {
        double parsedY = parseNumberWithSign(y_val);
        y = new DerivativeStructure(1, 0, parsedY); // 1 parameter, order 0, value y_val
    }

    @Given("^a DerivativeStructure \"x\" constructed with value (.+)$")
    public void a_DerivativeStructure_x_constructed_with_value(String x_val) {
        double parsedX = parseNumberWithSign(x_val);
        x = new DerivativeStructure(1, 0, parsedX); // 1 parameter, order 0, value x_val
    }

    @When("the method \"atan2\" is invoked with \"y\" and \"x\"")
    public void the_method_atan2_is_invoked_with_y_and_x() {
        try {
            result = DerivativeStructure.atan2(y, x);
        } catch (Exception e) {
            // Store the exception for later checking if needed
            System.out.println("Exception occurred: " + e.getMessage());
        }
    }

    @Then("^the value of the resulting DerivativeStructure should be (.+)$")
    public void the_value_of_the_resulting_DerivativeStructure_should_be(String expected_result) {
        double parsedExpected = parseNumberWithSign(expected_result);
        // Using a small tolerance for floating point comparison
        assertEquals(parsedExpected, result.getValue(), 1e-15);
    }

    @Then("^the sign of the value should be (.+)$")
    public void the_sign_of_the_value_should_be(String expected_sign) {
        double actualValue = result.getValue();
        double actualSign = Math.signum(actualValue);
        double parsedExpectedSign = parseNumberWithSign(expected_sign);
        assertEquals(parsedExpectedSign, actualSign, 1e-15);
    }

    private double parseNumberWithSign(String value) {
        if (value == null) {
            return 0.0;
        }
        try {
            // Handle special string values for signed zeros
            if ("+0.0".equals(value)) {
                return 0.0;  // Positive zero
            } else if ("-0.0".equals(value)) {
                return -0.0; // Negative zero
            } else {
                return Double.parseDouble(value);
            }
        } catch (NumberFormatException e) {
            // Handle parsing errors
            System.out.println("Could not parse number: " + value + ", returning 0.0");
            return 0.0;
        }
    }
}

