/** Compute two arguments arc tangent of a derivative structure.
 * @param y array holding the first operand
 * @param yOffset offset of the first operand in its array
 * @param x array holding the second operand
 * @param xOffset offset of the second operand in its array
 * @param result array where result must be stored (for
 * two arguments arc tangent the result array <em>cannot</em>
 * be the input array)
 * @param resultOffset offset of the result in its array
 */
public void atan2(final double[] y, final int yOffset,
                  final double[] x, final int xOffset,
                  final double[] result, final int resultOffset) {

    // Handle special cases for signed zeros according to IEEE 754
    final double yValue = y[yOffset];
    final double xValue = x[xOffset];

    // Check for special signed zero cases
    if (yValue == 0.0 && xValue == 0.0) {
        // atan2(+0, +0) returns +0
        // atan2(+0, -0) returns +π
        // atan2(-0, +0) returns -0
        // atan2(-0, -0) returns -π
        if (1.0 / yValue > 0) { // Check if y is +0 (not -0)
            if (1.0 / xValue > 0) { // x is +0
                result[resultOffset] = 0.0; // atan2(+0, +0) = +0
            } else { // x is -0
                result[resultOffset] = FastMath.PI; // atan2(+0, -0) = +π
            }
        } else { // y is -0
            if (1.0 / xValue > 0) { // x is +0
                result[resultOffset] = -0.0; // atan2(-0, +0) = -0
            } else { // x is -0
                result[resultOffset] = -FastMath.PI; // atan2(-0, -0) = -π
            }
        }

        // Set all higher order derivatives to 0
        for (int i = 1; i < result.length; ++i) {
            result[resultOffset + i] = 0.0;
        }
        return;
    }

    // compute r = sqrt(x^2+y^2)
    double[] tmp1 = new double[getSize()];
    multiply(x, xOffset, x, xOffset, tmp1, 0);      // x^2
    double[] tmp2 = new double[getSize()];
    multiply(y, yOffset, y, yOffset, tmp2, 0);      // y^2
    add(tmp1, 0, tmp2, 0, tmp2, 0);                 // x^2 + y^2
    rootN(tmp2, 0, 2, tmp1, 0);                     // r = sqrt(x^2 + y^2)

    if (x[xOffset] >= 0) {

        // compute atan2(y, x) = 2 atan(y / (r + x))
        add(tmp1, 0, x, xOffset, tmp2, 0);          // r + x
        divide(y, yOffset, tmp2, 0, tmp1, 0);       // y /(r + x)
        atan(tmp1, 0, tmp2, 0);                     // atan(y / (r + x))
        for (int i = 0; i < tmp2.length; ++i) {
            result[resultOffset + i] = 2 * tmp2[i]; // 2 * atan(y / (r + x))
        }

    } else {

        // compute atan2(y, x) = +/- pi - 2 atan(y / (r - x))
        subtract(tmp1, 0, x, xOffset, tmp2, 0);     // r - x
        divide(y, yOffset, tmp2, 0, tmp1, 0);       // y /(r - x)
        atan(tmp1, 0, tmp2, 0);                     // atan(y / (r - x))
        result[resultOffset] =
                ((tmp2[0] <= 0) ? -FastMath.PI : FastMath.PI) - 2 * tmp2[0]; // +/-pi - 2 * atan(y / (r - x))
        for (int i = 1; i < tmp2.length; ++i) {
            result[resultOffset + i] = -2 * tmp2[i]; // +/-pi - 2 * atan(y / (r - x))
        }

    }

